/**
 *
 * @namespace BXUI
 *
 */
const angular = require('angular');
const _ = require('lodash');

const PKG_JSON = require('json-loader!../../package.json');

const REGISTERED_MODULE_NAMES = [];

const BASE = {

    "register": _register,
    // package.json 파일에 할당된 version 정보를 가져온다.
    "version": PKG_JSON.version,
    "registerTopModule": _registerTopModule
};

/**
 * AngularJS 모듈 등록 함수
 *
 * @param {String} moduleName - 모듈 이름
 * @param {array}[$inject=[]] - $inject 배열
 * @param {object}[constructors={}] - directive, controller, service, template 생성자 함수 객체
 *
 * @private
 *
 * @memberof BXUI
 */
function _register(moduleName = '', $inject = [], {
    directive = null,
    controller = null,
    service = null,
    provider = null,
    template = null
    } = {}){

    if (!_.isString(moduleName) || moduleName === ''){
        throw new Error('moduleName 값이 존재하지 않습니다.');
    }

    if (!_.isArray($inject)){
        throw new Error('$inject 값이 존재하지 않습니다.');
    }

    const md = angular.module(moduleName, $inject);

    // 디렉티브 등록
    if (_.isObject(directive) && _.isFunction(directive.constructor)){
        directive.constructor.$inject = directive.$inject;
        md.directive(directive.name, directive.constructor);
    }

    // 컨트롤러 등록
    if (_.isObject(controller) && _.isFunction(controller.constructor)){
        controller.constructor.$inject = controller.$inject;
        md.controller(controller.name, controller.constructor);
    }

    // 서비스 등록
    if (_.isObject(service) && _.isFunction(service.constructor)){
        service.constructor.$inject = service.$inject;
        md.service(service.name, service.constructor);
    }

    // 프로바이더 등록
    if (_.isObject(provider) && _.isFunction(provider.constructor)){
        provider.constructor.$inject = provider.$inject;

        // provider name 에 대한 내부 처리 내용
        // 관련 링크: http://stackoverflow.com/questions/20881409/angularjs-injecting-a-provider
        md.provider(provider.name, provider.constructor);
    }

    // 템플릿 등록
    if (_.isObject(template) && _.isFunction(template.constructor)){
        template.constructor.$inject = template.$inject;
        md.run(template.constructor);
    }

    REGISTERED_MODULE_NAMES.push(moduleName);
}

function _registerTopModule(moduleName = ''){

    if (!_.isString(moduleName) || !_.trim(moduleName).length) moduleName = 'bx-ui';

    angular.module(moduleName, REGISTERED_MODULE_NAMES);
}


module.exports = BASE;
